const { ethers } = require("hardhat");

const POTENTIAL_ADDRS = [
    "0x0000000000000000000000000000000000000804", // The one I tried
    "0x0000000000000000000000000000000000000800", // Standard Xcm
    "0x0000000000000000000000000000000000000801", // XcmUtils?
    "0x0000000000000000000000000000000000000802", // XcmTransactor?
    "0x0000000000000000000000000000000000000803",
    "0x0000000000000000000000000000000000000805",
];

const XCM_MESSAGE_HEX = "";

async function main() {
    console.log("Probing addresses for weighMessage()...");
    const [deployer] = await ethers.getSigners();

    const iface = new ethers.Interface([
        "function weighMessage(bytes calldata message) external view returns (uint64 refTime, uint64 proofSize)"
    ]);

    for (const addr of POTENTIAL_ADDRS) {
        process.stdout.write(`Checking ${addr}... `);
        const contract = new ethers.Contract(addr, iface, deployer);
        try {
            const result = await contract.weighMessage(XCM_MESSAGE_HEX);
            console.log(`\n✅ FOUND at ${addr}!`);
            console.log("   RefTime:", result.refTime.toString());
            console.log("   ProofSize:", result.proofSize.toString());
            return;
        } catch (e) {
            console.log("❌");
            // console.log(e.message);
        }
    }
    console.log("\n❌ Not found on any common address.");
}

main().catch(console.error);
